234: function buildFactsSection(facts: LedgerFactLike[], charName: string, userName: string): string {
235:   if (facts.length === 0) return "";
236:   const ordered = FACT_CATEGORY_ORDER.flatMap((cat) => facts.filter((f) => f.category === cat));
