273: function buildLoreSection(entries: LoreEntryLike[], charName: string, userName: string): string {
274:   if (entries.length === 0) return "";
275:   const lines = entries.map((e) => `- ${substitutePlaceholders(e.content.trim(), charName, userName)}`);
276:   return `[Poznámky ze světa — lorebook]\n${lines.join("\n")}`;
277: }
