285:   if (memories.length === 0) return "";
286:   return `[RELEVANTNÍ VZPOMÍNKY — starší scény, doslovně]\n${memories
287:     .map((m) => `---\n${m.trim()}`)
288:     .join("\n")}`;
289: }
290: 
291: function assembleSystemMessage(sections: string[]): string {
292:   return sections.filter(Boolean).join("\n\n");
293: }
