314:   let summaryTruncated = false;
315:   let mesExampleIncluded = character.mesExample.trim().length > 0;
316: 
317:   const historyTotal = input.history.length;
318:   let historyIncluded = input.history.slice(-verbatimWindow);
319: 
320:   const groupMembers = input.groupMembers ?? [];
