326:     sectionsTokens: [redacted]
327:     canonReminderTokens: [redacted]
328:   } {
329:     const mesExampleSection = mesExampleIncluded ? buildMesExampleSection(character, charName, userName) : "";
330:     const factsSection = buildFactsSection(facts, charName, userName);
331:     const loreSectionEntries = [...lore].sort((a, b) => b.priority - a.priority);
332:     const loreSection = buildLoreSection(loreSectionEntries, charName, userName);
333:     const summarySection = buildSummarySection(summaryText);
334:     const memoriesSection = buildMemoriesSection(memories);
335: 
336:     const systemText = assembleSystemMessage([
337:       systemCore,
338:       mesExampleSection,
339:       factsSection,
340:       loreSection,
341:       summarySection,
342:       memoriesSection,
343:     ]);
344: 
345:     const messages: PromptMessage[] = [];
346:     if (systemText) messages.push({ role: "system", content: systemText });
347:     for (const m of historyIncluded) messages.push(m);
348:     let phi = character.postHistoryInstructions.trim();
349:     if (groupMembers.length > 0) {
350:       const groupInstruction = buildGroupSpeakerInstruction(groupMembers.map((m) => m.name));
351:       phi = phi ? `${phi}\n\n${groupInstruction}` : groupInstruction;
352:     }
353:     // Canon reminder is appended last, closest to generation — see
354:     // `buildCanonReminderSection`. It is intentionally NOT part of the
355:     // budget-trim passes below (never cut), only size-capped at build time.
356:     const canonSection = buildCanonReminderSection(facts, charName, userName);
357:     if (canonSection) {
358:       phi = phi ? `${phi}\n\n${canonSection}` : canonSection;
359:     }
